var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래. 돌아올 거라고 믿어 주는 사람을 주인으로 모시고 싶다, 라......","JPN":"そう。帰ってくると信じてくれる人を主にしたい、と……","ENG":"I see... So you want to serve someone who trusts you to return...","TWN":"侍奉堅信自己會回來的人為主人……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"근사한 고백이네. 이 자리에 참석하지 않아서 듣지 못한 당사자가 안타까울 정도야.","JPN":"中々素敵な告白じゃない。本人がこの場にいなくて残念だわ。","ENG":"What a most touching declaration of your fealty. It's almost unfortunate that he's not here to hear it himself.","TWN":"真是讓人感動啊，那個人不能親耳聽到，真是可惜了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 아쉽겠어, 베로니카.","JPN":"でもお気の毒ね、ベロニカ。","ENG":"It's too bad, Veronica.","TWN":"但是非常遺憾，貝洛妮卡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그 말은 이루어질 수 없거든.","JPN":"その言葉は叶わないの。","ENG":"Because that new aspiration can't come true.","TWN":"恐怕你無法實現你的願望了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"영원히.","JPN":"永遠にね。","ENG":"Ever.","TWN":"永遠。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"리, 리코리스님! 이상한 사람들이 잔뜩 나타났슴다!","JPN":"リ、リコリス様！　変な人がいっぱい出てきたっす！","ENG":"M-Miss Lycoris! A bunch of weirdos appeared, ma'am!","TWN":"莉、莉克麗絲大人！突然出現了好多奇怪的人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저 시커먼 녀석들은 뭐야......? 맨션에 잠입해 있던 동안 한 번도 못 봤는데?","JPN":"あの真っ黒なやつらはなに……？　マンションにいる時もあんなの見たことなかったわ！","ENG":"W-who the hell are they? I never saw them the whole time I have been undercover at the Mansion!","TWN":"那些黑色東西是什麼……？我在曼森的期間從來沒見過她們啊？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"인사하렴. 이 아이들은 그레이 리프라고 한단다.","JPN":"さあ、挨拶しなさい。この子たちはグレーリーフよ。","ENG":"Say hello. I call these children the Gray Leaves.","TWN":"打個招呼吧，她們叫格雷麗芙。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"내가 배합한 식물독으로 뇌까지 가꿔 준 아이들이지.","JPN":"私が配合した植物毒で脳の髄まで綺麗に育てあげたの。","ENG":"I've personally tended to their brains with my plant poison concoction.","TWN":"我用親自調配的植物毒液重新培養了她們的大腦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 사람들은......","JPN":"その方たちは……","ENG":"They are...","TWN":"這些人……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"활동 중에 실종됐다고 알려진 전대 메이드장들이군요.","JPN":"活動中に失踪したと言われた先代のメイド長たちですね。","ENG":"They are the former Chief Maids who supposedly went missing during their service.","TWN":"是執行任務時，所失蹤的前任女僕長們。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"설마 당신이 그녀들을 숨겨두고 있던 겁니까?","JPN":"まさかあなたが彼女たちを……？","ENG":"So you were hiding them?","TWN":"原來你一直把她們藏起來了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"눈썰미가 좋구나.","JPN":"さすがだわ。","ENG":"How observant of you.","TWN":"不笨嘛。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"재능은 가졌지만 가망이 없던 아이들에게 새로운 쓰임새를 만들어 준 거지.","JPN":"才能はあるけど見込みがなかった子に、新しい使い道を切り開いてあげたのよ。","ENG":"I've given new purpose to those who were talented but weren't quite promising enough.","TWN":"她們雖然有才華，但她們沒有任何可能性，所以我賜予了她們全新的角色。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"가망?","JPN":"見込み？","ENG":"Promising enough for what?","TWN":"可能性？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"맨션의 차기 주인이 될 가능성 말이야.","JPN":"マンションの次期主になる可能性のことよ。","ENG":"To become the next Master of the Mansion.","TWN":"成為曼森下一個主人的可能性。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"나도 꽤 오래 맡았다고 생각하는데...... 그간 눈에 띄는 재목이 없었거든.","JPN":"私もずいぶん長い間この仕事をやってきたけど……これまで目につく人材がいなくて。","ENG":"I've felt that I've been at this for far too long... but I couldn't find anyone worthy.","TWN":"我在這個位置也很久了……期間也沒有出現過讓人眼前一亮的人才。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"네가 나타나기 전까진 말이지. 베로니카.","JPN":"あなたが現れるまではね、ベロニカ。","ENG":"That is, until I found you, Veronica.","TWN":"直到你的出現，貝洛妮卡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRAY_NPC_MANSION_NULL","text":{"KOREA":"마스터. 준비가 끝났습니다.","JPN":"マスター、用意ができました。","ENG":"The preparations are ready, Master.","TWN":"主人，已經準備好了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼 작별인사를 할 시간이구나. 배웅은 나와 줬으니 섭섭해하지 마렴.","JPN":"それじゃあ、お別れの時間よ。見送りはするから寂しがらないでね。","ENG":"So it's time to bid adieu. I hope you won't be too disheartened. After all, I came to say goodbye personally.","TWN":"是時候道別了，我好歹親自來送你一場，就不要感到遺憾了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"자, 잠깐! 지금 무슨 소리야! 배웅이라니?!","JPN":"ま、待って！　どういうことなの？　見送り！？","ENG":"W-wait a minute! What do you mean goodbye?","TWN":"等、等等！你在說什麼！送一場？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"아무리 아름다운 꽃이라고 해도 화분에 심어 기를지, 벽난로의 땔감으로 쓸지는 전적으로 주인이 정하는 거란다.","JPN":"いくら美しい花でも植木鉢に植えるか暖炉の薪として使うかは、すべて主が決めること。","ENG":"Even the most beautiful flower is at the mercy of its master; whether she will be tended in a pot or tossed in the hearth for fuel.","TWN":"無論是多麼美麗的花，養在花盆還是扔進壁爐，全憑主人決定。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"정성껏 기른 꽃을 이렇게 태워버리게 돼서 아쉽지만......","JPN":"丹精込めて育てた花を燃やすことになって残念ではあるけど……","ENG":"Although it does sadden me that I must burn a flower I've raised with such great care...","TWN":"我費盡了心思養的花，只能就這麼燒掉，確實很可惜……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 어쩔 수 없지.","JPN":"まあ、仕方ないわね。","ENG":"Oh well, it is what it is.","TWN":"不過，也沒辦法了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"사랑하는 꽃봉오리가 흉하게 시드는 꼴을 보는 것보다는 이 편이 나을 테니까.","JPN":"愛しいつぼみが醜く枯れていく様を見るよりは、この方がマシだわ。","ENG":"This is a far better alternative to seeing my beloved blossoms wither horrendously.","TWN":"與其看著我親愛的花蕾醜陋地凋零下去，還不如就這麼燒掉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"설마 이 건물......! 처음부터 폭탄이 설치되어 있었던 거야?!","JPN":"まさかこの建物……！　最初から爆弾が仕掛けられていたの！？","ENG":"Wait... Has this building been rigged to blow all along?","TWN":"難道這個建築……！一開始就埋設了炸彈？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후훗. 기폭시켜.","JPN":"フフッ。起爆して。","ENG":"Hah hah. Detonate the bombs.","TWN":"呼呼，引爆吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRAY_NPC_MANSION_NULL","text":{"KOREA":"명령에 따르겠습니다. 마스터.","JPN":"御意、マスター。","ENG":"As you wish, Master.","TWN":"遵命，主人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"의식이...... 흐려져 가......","JPN":"意識が……遠ざかる……","ENG":"I'm... fading away...","TWN":"意識……越來越模糊了……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이걸로...... 끝인가......?","JPN":"これで……おしまいでしょうか……？","ENG":"Is this... the end?","TWN":"難道就這麼……結束了……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"미안해요, 릴리...... 모네......","JPN":"ごめんなさい、リリー……モネ……","ENG":"I'm sorry, Lily... Mone...","TWN":"對不起，莉莉……莫妮……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"죄송합니다. 주인님......","JPN":"申し訳ありません、ご主人様……","ENG":"I'm sorry, Master...","TWN":"對不起，主人……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 이 역시 제가 저지른 죄의 대가를 치르는 것이겠죠.","JPN":"しかしこれもまた、自分の罪の代償を払うということなのでしょう。","ENG":"But I suppose this is the way I must atone for my sins.","TWN":"這就是我為我犯下的罪所付出的代價吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"모두들...... 부디 무사하시길......","JPN":"皆様……どうかご無事でありますように……","ENG":"I hope... you are all alright...","TWN":"希望大家……都能安好……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"죄의 대가라는 건 그렇게 쉽게 갚을 수 있는 게 아닐세.","JPN":"罪の代償というものは、そう簡単に払えるものではないぞ。","ENG":"I'm afraid atonement doesn't come that easily.","TWN":"想為犯下的罪付出代價，可沒那麼容易。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......주인님?","JPN":"……ご主人様？","ENG":"Master?","TWN":"……主人？"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님의 목소리가...... 어떻게......","JPN":"ご主人様の声が……どうして……","ENG":"How am I hearing your voice...","TWN":"主人的聲音……怎麼會……"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잊고 있었나 보군.","JPN":"忘れてしまったのかね。","ENG":"Oh, I guess you forgot.","TWN":"你忘了嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 준 휴가 티켓, 품 안에 잘 간직하고 있지 않나.","JPN":"この前渡した休暇チケット、ちゃんと持っているじゃないか。","ENG":"You've still got that leave coupon I gave you, no?","TWN":"你身上還帶著我給你的休假券呢。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 정도 크기의 물체라면 몇 가지 기능을 추가하는 잔재주쯤은 별로 어렵지 않지.","JPN":"そのくらいの大きさの物になら、いくつか機能を追加するくらいの小細工はさほど難しくないんだ。","ENG":"Adding a few features to something of that size is just the sort of trick I'm good at.","TWN":"在那個東西上加幾個功能對我來說是小意思。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님......","JPN":"マスター……","ENG":"Master...","TWN":"主人……"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"죽음으로 속죄하는 건 불가능해.","JPN":"死で贖罪することはできない。","ENG":"You cannot atone for anything with death.","TWN":"以死贖罪是不可能的。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 이 세상에서...... 아니, 우주 전체를 통틀어서 내가 가장 잘 알고 있지.","JPN":"それはこの世界で……いや、宇宙全体で私が一番よく知っている。","ENG":"I of all people know that better than anyone in this world... or anyone in this universe.","TWN":"在這個世界……哦不，在整個宇宙中沒有人比我更清楚這個道理。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 일어나게. 자네를 기다리는 사람들이 아직 여기에 있지 않나.","JPN":"だから立ち上がってくれ。君を待っている人たちがまだここにいるのではないか。","ENG":"So get up now. There are still those who are counting on you.","TWN":"起來吧，這裡還有很多人等著你。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나를 포함해서 말이야.","JPN":"私を含めてね。","ENG":"Including me.","TWN":"包括我。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만......","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 제 몸은 이제 더 이상...... 움직이지 않습니다.","JPN":"ですが私の身体はこれ以上……動けません。","ENG":"My body will no longer move.","TWN":"但是我的身體……已經動不了了。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"손발의 감각도 오래 전부터......","JPN":"手足の感覚もとっくの昔に……","ENG":"I lost the sensation in my hands and feet a long time ago...","TWN":"手腳的感覺很早就……"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"느껴지고 있어......?","JPN":"感じられる……？","ENG":"... but it's coming back?","TWN":"你感受到了嗎……？"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"감각이...... 돌아오고 있어요.","JPN":"感覚が……戻ってきています。","ENG":"The sensations... are coming back.","TWN":"我的感覺……正在恢復。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"추위도, 아픔도...... 이건 대체......?","JPN":"寒さも、痛みも……これはいったい……？","ENG":"I can even feel the coldness... and the pain... But how?","TWN":"寒冷和疼痛也……這到底是……？"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말하지 않았나. 이런 잔재주가 내 특기라고 말이야.","JPN":"言ったじゃないか。このような小細工は私の特技であると。","ENG":"Like I said, I'm good with little tricks like that.","TWN":"我不是說了，我有很多小功能。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"신경에 뿌리내린 독을 잠시 중화하는 기능 정도는 별거 아니지.","JPN":"神経に根づいた毒をしばらく中和する機能程度は、簡単なことさ。","ENG":"Temporarily neutralizing the chemicals that poisoned your nervous system was a piece of cake.","TWN":"暫時中和侵入神經的毒液，對我來說簡直是小菜一碟。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자극을 받으면 몸이 움직이게 돼. 자네 일을 마무리할 때까지는 버텨 줄 거야.","JPN":"刺激を受けたら体が動き出す。君がその仕事を仕上げるまでは持つだろう。","ENG":"Your body will move again with stimulus. It should hold up until you're done with the job.","TWN":"受到刺激後身體就可以動起來，可以撐到你完成你的事為止。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"싸움에는 별로 자신이 없지만 주인으로서, 아니 친구로서 손 정도는 잡아줄 수 있네.","JPN":"戦いにはあまり自信はないが、主として、いや友達として背中を押すことはできる。","ENG":"I'm not much of a fighter, but the least I can do is hold your hand as your master... or rather, your friend.","TWN":"雖然我不擅長打架，但作為主人，哦不，作為朋友，我可以拉你一把。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 일어서게. ","JPN":"さあ、立ち上がってくれ。 ","ENG":"So get up now. ","TWN":"快起來吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로 달려나갈 시간이야.","JPN":"前に進む時が来たのさ。","ENG":"It's time to move forward.","TWN":"是時候向前衝了。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"시원스럽게 무너지는 모습이 꽃들의 무덤으로 잘 어울리겠는걸.","JPN":"派手に崩れていく様が花たちの墓場として、とてもふさわしいわね。","ENG":"This rubble will make a fabulous grave for those flowers.","TWN":"你倒下的樣子很適合做花朵的墳墓。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이런, 옷에 먼지가 앉았네. 새로 산 드레스인데 아깝게.","JPN":"あら、服が埃まみれじゃない。新品のドレスなのに勿体ないわ。","ENG":"Oh my. I've got dust on my new dress.","TWN":"衣服上落了灰，這可是剛買的裙子，真是可惜了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRAY_NPC_MANSION_NULL","text":{"KOREA":"걱정 마십시오. 세탁 담당들을 대기시켜 두겠습니다.","JPN":"ご心配なさらず。洗濯担当を待機させておきます。","ENG":"Don't worry. We'll have the laundry maids standby.","TWN":"您不用擔心，我會讓負責洗衣服的人候著的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래, 목욕물도 좀 받아 두게 하렴.","JPN":"いいわね。お風呂の用意もお願い。","ENG":"Oh, good. Have them run a bath for me, too.","TWN":"好，順便讓她們備點洗澡水。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"몸을 녹이면서 누굴 새로운 메이드장을 세울지 고민 좀 해야겠어.","JPN":"湯船に浸かりながら誰を次期メイド長にするか悩んでみるわ。","ENG":"While soaking myself in a hot tub, I'll have to think about whom to appoint as the next Chief Maid.","TWN":"我要暖一暖我的身子，順便想想讓誰當下一任女僕長。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"고민할 필요 없습니다, 마스터.","JPN":"その悩みは不要です、マスター。","ENG":"I'll save you the trouble.","TWN":"不用考慮了，主人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_12"},{"id":"L20_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"응?","JPN":"あら？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"방금 이 목소리...... 잔해 속에서 들린 건가?","JPN":"この声は……残骸の中から聞こえた？","ENG":"That voice just now... Did it come from the rubble?","TWN":"這個聲音……是從殘骸裡傳出來的？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"누가 메이드장이 되든 간에, 제가 당신으로부터 그녀들을 해방시킬 테니까요.","JPN":"誰がメイド長になろうと、私があなたから彼女たちを解放しますから。","ENG":"Regardless of who becomes the next Chief Maid, I will liberate her from you.","TWN":"因為無論由誰當下一任女僕長，我都會從你的手中解救她們。"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_13"},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"베로니카......?","JPN":"ベロニカ……？","ENG":"Veronica?","TWN":"貝洛妮卡……？"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럴 리가......! 그 폭발에서 살아남았다고?","JPN":"そんなはずが……！　あの爆発から生き延びたの？","ENG":"Impossible! You survived the blast?","TWN":"怎麼可能……！你怎麼還活著？"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"말씀드리지 않았나요, 마스터. 주인님께서 돌아온다고 믿어 주셨습니다.","JPN":"申し上げたはずです、マスター。我が主は私が戻ると信じてくれたのです。","ENG":"Haven't I told you? My new master trusts me to return.","TWN":"我說過，我的主人堅信我會回來。"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_14"},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"메이드란 주인의 뜻을 이루어 드리는 삶의 형태.","JPN":"メイドとはご主人様の望みを叶える生き方をする者。","ENG":"A maid is someone who serves her master to do their bidding.","TWN":"女僕就是一生追隨主人，按照主人的意願而活的人。"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_15"},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께서 제가 돌아오길 바라시는 한......","JPN":"ご主人様が私の帰りを望んでいる以上……","ENG":"As long as my new master wishes for me to return...","TWN":"如果主人希望我回去……"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_16"},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"전, 몇 번이고 살아서 돌아갈 겁니다.","JPN":"私は何度でも蘇って、ご主人様のもとへ戻ります。","ENG":"That is what I will do, no matter what it takes.","TWN":"那我就必須千方百計地活著回去。"},"stage":{"bg":"SS_MAID_03","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_17"},{"id":"L35_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"......끈질기구나. 베로니카. 정이 떨어질 만큼 끈질겨.","JPN":"……しつこいわね、ベロニカ。うんざりするほど、しつこい。","ENG":"You're tenacious, Veronica. So tenacious that it makes me sick.","TWN":"……你很執著，貝洛妮卡，執著到讓我討厭。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"더 이상은 지켜볼 마음이 사라졌어. 얘들아?","JPN":"これ以上は見てやれないわ。みんな！","ENG":"I no longer feel so inclined to see you in full bloom. Girls?","TWN":"我現在不想看見你了，孩子們？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"먼저 갈 테니 당장 저 꽃을 꺾어 버리렴.","JPN":"先に帰るから今すぐあの花を折ってしまいなさい。","ENG":"I'll be going now. Go pluck that flower at once.","TWN":"我先走了，你們給我折了那朵花吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"GRAY_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};